package trackerweb

const workersTemplate = `{{define "workers"}}<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Workers · SavewebHQ</title><link rel="stylesheet" href="/assets/admin.css"></head><body><header><a class="brand" href="/admin">SavewebHQ</a></header><main><div class="breadcrumbs"><a href="/admin">Projects</a><span>/</span><span>Workers</span></div><div class="page-title"><div><h1>Workers</h1><p>{{if .WorkerID}}Exact match for <code>{{.WorkerID}}</code>{{else}}First 200 mappings{{end}}</p></div><form method="get" action="/admin/workers" class="inline-form"><label>Worker ID<input name="worker_id" value="{{.WorkerID}}" maxlength="128" pattern="[A-Za-z0-9._:-]+" required></label><button type="submit">Find</button>{{if .WorkerID}}<a class="button" href="/admin/workers">Clear</a>{{end}}</form></div><section class="table-wrap"><table><thead><tr><th>Worker ID</th><th>User ID</th></tr></thead><tbody>{{range .Workers}}<tr class="{{if eq .WorkerID $.WorkerID}}selected-row{{end}}"><td><code>{{.WorkerID}}</code></td><td><a href="/admin/users?user_id={{.UserID}}#user-form"><code>{{.UserID}}</code></a></td></tr>{{else}}<tr><td colspan="2" class="empty">No worker mapping found</td></tr>{{end}}</tbody></table></section></main></body></html>{{end}}`
